option.value:
* {
	box-sizing: border-box;
}

body {
	margin: 0;
	font-family: Arial, sans-serif;
	background-color: #f2f2f2;
	color: #111;
}

.page-center {
	min-height: 100vh;
	display: flex;
	align-items: center;
	justify-content: center;
	padding: 24px;
}

.login-dialog {
	width: 100%;
	max-width: 360px;
	background-color: #fff;
	border: 2px solid #000;
	border-radius: 16px;
	padding: 28px 24px;
}

.dialog-title {
	margin: 0 0 20px;
	text-align: center;
	font-size: 28px;
	font-weight: 700;
	color: #000;
}

.dialog-content {
	display: grid;
	gap: 12px;
}

.dialog-content input,
.dialog-actions button {
	width: 100%;
	height: 42px;
	border-radius: 10px;
	border: 1px solid #000;
	padding: 0 12px;
	font-size: 15px;
	background-color: #fff;
	color: #000;
}

.dialog-actions {
	display: grid;
	grid-template-columns: 1fr 1fr;
	gap: 12px;
}

.dialog-actions button {
	font-weight: 700;
	cursor: pointer;
}

.dialog-actions button:hover {
	background-color: #000;
	color: #fff;
}

.editor-page {
	min-height: 100vh;
	display: flex;
	align-items: stretch;
	justify-content: space-between;
	gap: 24px;
	padding: 24px;
}

.editor-left,
.editor-right {
	flex: 1;
	display: flex;
	align-items: center;
	justify-content: center;
}

.editor-middle {
	width: 200px;
	display: flex;
	flex-direction: column;
	align-items: stretch;
	justify-content: center;
	position: sticky;
	top: 50%;
	align-self: flex-start;
	transform: translateY(-50%);
}

.middle-actions {
	width: 100%;
	display: grid;
	grid-template-columns: 1fr;
	gap: 8px;
}

.info-list {
	width: 100%;
	margin-top: 12px;
	height: 220px;
	overflow-y: auto;
}

.middle-actions button {
	height: 38px;
	border: 1px solid #111;
	border-radius: 8px;
	background-color: #fff;
	color: #111;
	font-size: 14px;
	font-weight: 700;
	cursor: pointer;
}

.middle-actions button:hover {
	background-color: #111;
	color: #fff;
}

#createFile {
	width: 100%;
	padding: 10px;
	border: 1px solid #bbb;
	border-radius: 8px;
	background-color: #fff;
}

#fileNameInput {
	width: 100%;
	height: 38px;
	border: 1px solid #bbb;
	border-radius: 8px;
	padding: 0 10px;
	font-size: 14px;
	background-color: #fff;
	color: #111;
	margin-bottom: 8px;
}

#fileNameInput:focus {
	border-color: #111;
	outline: none;
}

#createFileBtn {
	width: 100%;
	height: 38px;
	border: 1px solid #111;
	border-radius: 8px;
	background-color: #fff;
	color: #111;
	font-size: 14px;
	font-weight: 700;
	cursor: pointer;
}

#createFileBtn:hover {
	background-color: #111;
	color: #fff;
}

.grid-panel {
	padding: 8px;
}

.editor-right {
	flex-direction: column;
	align-items: center;
	justify-content: center;
	padding: 8px;
}

.log-title {
	width: 100%;
	max-width: 420px;
	margin: 0 0 12px;
	font-size: 22px;
	font-weight: 700;
	color: #111;
}

.log-list {
	width: 100%;
	max-width: 420px;
	height: 560px;
	padding: 8px;
	border: 1px solid #bbb;
	border-radius: 8px;
	background-color: #fff;
	overflow-y: auto;
}

.log-item {
	margin: 0;
	padding: 14px 10px;
	border-bottom: 1px solid #eee;
	color: #111;
}

.log-item:last-child {
	border-bottom: none;
}

.edit-controls {
	display: grid;
	gap: 8px;
	margin-bottom: 10px;
}

.edit-controls label {
	display: grid;
	gap: 6px;
	font-size: 13px;
	font-weight: 600;
}

.edit-controls input {
	height: 38px;
	border: 1px solid #bbb;
	border-radius: 8px;
	padding: 0 10px;
	font-size: 14px;
	background-color: #fff;
	color: #111;
}

.edit-actions {
	display: grid;
	grid-template-columns: 1fr;
	gap: 8px;
	margin-bottom: 12px;
}

.edit-actions button {
	height: 38px;
	border: 1px solid #111;
	border-radius: 8px;
	background-color: #fff;
	color: #111;
	font-size: 14px;
	font-weight: 700;
	cursor: pointer;
}

.edit-actions button:hover {
	background-color: #111;
	color: #fff;
}

.grid-board {
	display: grid;
	grid-template-columns: repeat(4, 56px);
}

.grid-cell {
	width: 56px;
	height: 56px;
	border: none;
	background-color: #dbeafe;
	box-shadow: none;
}

.file-entry:hover {
    cursor: pointer;
    color: red;
}

* {
	box-sizing: border-box;
}

